solutions.javascript:
// Solution
import React, { useState, useEffect } from 'react';

function SumArray({ nums }) {
  const memoizedSum = React.useMemo(() => nums.reduce((a, b) => a + b, 0), [nums]);
  return <div>Sum: {memoizedSum}</div>;
}
